import { initializeApp } from 'firebase/app';
import { getAuth, connectAuthEmulator } from 'firebase/auth';
import { connectFirestoreEmulator, initializeFirestore } from 'firebase/firestore';

const firebaseConfig = {
  apiKey: 'AIzaSyDzNNTDr9GcChmWOHn4zgIcCMIIkQy5L3c',
  authDomain: 'thisai-spokenenglish.firebaseapp.com',
  projectId: 'thisai-spokenenglish',
  storageBucket: 'thisai-spokenenglish.firebasestorage.app',
  messagingSenderId: '388195300228',
  appId: '1:388195300228:web:7646341bb70680e73de3d1'
};

export const firebaseApp = initializeApp(firebaseConfig);
export const auth = getAuth(firebaseApp);
export const db = initializeFirestore(firebaseApp, {
  experimentalAutoDetectLongPolling: true,
  experimentalForceLongPolling: true
});

const useEmulators = process.env.EXPO_PUBLIC_USE_EMULATORS === 'true';
const emulatorHost = process.env.EXPO_PUBLIC_FIREBASE_EMULATOR_HOST || '127.0.0.1';

if (useEmulators) {
  connectAuthEmulator(auth, `http://${emulatorHost}:9099`, { disableWarnings: true });
  connectFirestoreEmulator(db, emulatorHost, 8080);
}

export default firebaseApp;
